INSERT INTO `files` (`id`, `name`, `content`, `service_id`, `service_name`, `created_at`, `updated_at`) VALUES (4, 'docker-compose-middleware.yml', 'version: \'3\'\nservices:\n  # mysql配置\n  mysql:\n    # 使用mysql8版本镜像\n    image: mysql:8.0\n    deploy:\n      resources:\n        limits:\n          memory: 512m\n    # 设置自启\n    restart: always\n    # 容器名\n    container_name: mysql\n    # mysql root用户密码配置\n    environment:\n      MYSQL_ROOT_PASSWORD: milliondao123456\n    # mysql基础配置\n    command:\n      --max_allowed_packet=32M\n      --max_connections=1000\n    # 端口绑定\n    ports:\n      - \"3306:3306\"\n    # 数据卷(需要在宿主机新建对应空文件)\n    volumes:\n      - \"/root/mysql/conf/my.cnf:/etc/mysql/conf.d/my.cnf\"\n      - \"/root/mysql/data:/var/lib/mysql\"\n      - \"/root/mysql/error.log:/var/log/mysql/error.log\"\n    ulimits:    # 增加系统资源限制\n      nofile:\n        soft: 65535\n        hard: 65535\n  # mysql配置\n  redis:\n    image: redis\n    deploy:\n      resources:\n        limits:\n          memory: 256m\n    restart: always\n    container_name: redis\n    privileged: true\n    ports:\n      - \"6379:6379\"\n    environment:\n      TZ: Asia/Shanghai\n    volumes:\n      - \"/root/redis/conf/data:/data\"\n      - \"/root/redis/conf/redis.conf:/etc/redis/redis.conf\"\n      - \"/root/redis/conf/logs:/logs\"\n    command: [ \"redis-server\",\"/etc/redis/redis.conf\" ]\n  mongodb:\n    image: mongo:latest\n    deploy:\n      resources:\n        limits:\n          memory: 256m\n    restart: always\n    container_name: mongodb\n    privileged: true\n    ports:\n      - \"27017:27017\"\n    volumes:\n      - \"/root/mongo/db:/data/db\"\n    environment:\n      MONGO_INITDB_ROOT_USERNAME: root\n      MONGO_INITDB_ROOT_PASSWORD: milliondao123456\n    command: [--bind_ip_all]\n  kafka:\n    image: apache/kafka:latest  # 使用支持 Kraft 模式的 Kafka 版本\n    deploy:\n      resources:\n        limits:\n          memory: 512m\n    container_name: kafka\n    ports:\n      - \'9092:9092\'  # 将 Kafka 的默认端口映射到主机\n      - \'29092:29092\'\n    environment:\n      KAFKA_KRAFT_MODE: \"true\"  # 启用 Kraft 模式以取代 Zookeeper\n      KAFKA_PROCESS_ROLES: \"broker,controller\"  # 定义 Kafka 的角色为 broker 和 controller\n      KAFKA_NODE_ID: 1  # Kafka 节点的唯一 ID\n      KAFKA_LISTENERS: \"SASL_PLAINTEXT://:9092,CONTROLLER://:29092\"  # 配置 Kafka 的监听接口\n      KAFKA_HEAP_OPTS: \"-Xms256M -Xmx256M -XX:+UseG1GC -XX:MaxGCPauseMillis=20\"\n      KAFKA_LISTENER_SECURITY_PROTOCOL_MAP: \"SASL_PLAINTEXT:SASL_PLAINTEXT,CONTROLLER:PLAINTEXT\"  # 定义监听器的协议映射\n      KAFKA_ADVERTISED_LISTENERS: \"SASL_PLAINTEXT://kafka.mgface.com:9092\"\n      KAFKA_INTER_BROKER_LISTENER_NAME: \"SASL_PLAINTEXT\"  # 用于 broker 之间通信的监听器名称\n      KAFKA_CONTROLLER_LISTENER_NAMES: \"CONTROLLER\"  # 定义控制器使用的监听器名称\n      KAFKA_CONTROLLER_QUORUM_VOTERS: \"1@kafka:29092\"  # 配置控制器投票者\n      KAFKA_LOG_DIRS: \"/var/lib/kafka/data\"  # 数据文件存储目录\n      KAFKA_OFFSETS_TOPIC_REPLICATION_FACTOR: 1  # 设置偏移量主题的复制因子\n      KAFKA_TRANSACTION_STATE_LOG_REPLICATION_FACTOR: 1  # 定义事务状态日志的复制因子\n      KAFKA_TRANSACTION_STATE_LOG_MIN_ISR: 1  # 事务日志的最小同步副本\n      KAFKA_MIN_INSYNC_REPLICAS: 1  # 最小同步副本数\n      KAFKA_BROKER_ID: 1  # Broker 的唯一 ID\n      KAFKA_LOG4J_LOGGERS: \"kafka.controller=INFO,state.change.logger=INFO\"  # 定义特定日志类别的日志级别\n      # SASL 配置\n      KAFKA_SASL_ENABLED_MECHANISMS: \"PLAIN\"\n      KAFKA_SASL_MECHANISM_INTER_BROKER_PROTOCOL: \"PLAIN\"\n      KAFKA_AUTHORIZER_CLASS_NAME: \"org.apache.kafka.metadata.authorizer.StandardAuthorizer\"\n      KAFKA_ALLOW_EVERYONE_IF_NO_ACL_FOUND: \"true\"\n\n      # 自定义 JAAS 文件路径\n      KAFKA_OPTS: \"-Djava.security.auth.login.config=/etc/kafka/kafka_server_jaas.conf\"\n      # 允许更大消息（设置为200MB）\n      KAFKA_MESSAGE_MAX_BYTES: 10485760\n      KAFKA_REPLICA_FETCH_MAX_BYTES: 10485760\n      KAFKA_FETCH_MESSAGE_MAX_BYTES: 10485760\n    volumes:\n      - \"/root/kafka/data:/var/lib/kafka/data\"  # 持久化 Kafka 数据到本地目录\n      - \"/root/kafka/logs:/var/log/kafka\"  # 将 Kafka 容器的日志输出到本地主机目录\n      - \"/root/kafka/kafka_server_jaas.conf:/etc/kafka/kafka_server_jaas.conf\"  # 挂载 JAAS 配置', 3, '中间件-mysql|mongo|kafka|redis', '2025-03-14 14:18:35', '2025-04-17 12:56:55');
