INSERT INTO `files` (`id`, `name`, `content`, `service_id`, `service_name`, `created_at`, `updated_at`) VALUES (10, 'server_init.sh', '#!/bin/bash\nset -e  # 任何命令失败立即退出脚本\n\n\n# 添加 Docker 官方 GPG 密钥\ncurl -fsSL https://download.docker.com/linux/ubuntu/gpg | sudo gpg --dearmor -o /usr/share/keyrings/docker-archive-keyring.gpg\n\n# 安装 Docker 的依赖项\nsudo apt update\nsudo apt install -y \\\n    apt-transport-https \\\n    ca-certificates \\\n    curl \\\n    software-properties-common \\\n    gnupg\n\n\n# 设置 Docker 稳定版仓库\necho \"deb [arch=$(dpkg --print-architecture) signed-by=/usr/share/keyrings/docker-archive-keyring.gpg] https://download.docker.com/linux/ubuntu $(lsb_release -cs) stable\" | sudo tee /etc/apt/sources.list.d/docker.list > /dev/null\n\n# 安装 Docker 引擎\nsudo apt update\nsudo apt install -y \\\n    docker-ce \\\n    docker-ce-cli \\\n    containerd.io\n\n# 启动 Docker 服务并设置开机自启\nsudo systemctl enable --now docker\n\n# 添加当前用户到 docker 用户组（需要重新登录生效）\nsudo usermod -aG docker $USER\necho \"[注意] 用户已加入 docker 组，请注销后重新登录生效\"\n\n# 安装 docker-compose\nCOMPOSE_VERSION=\"v2.20.0\"\nsudo curl -L \"https://github.com/docker/compose/releases/download/${COMPOSE_VERSION}/docker-compose-$(uname -s)-$(uname -m)\" \\\n    -o /usr/local/bin/docker-compose\nsudo chmod +x /usr/local/bin/docker-compose\n\n# 安装 sysstat 并启用数据收集\nsudo apt install -y sysstat\nsudo sed -i \'s/ENABLED=\"false\"/ENABLED=\"true\"/\' /etc/default/sysstat\nsudo systemctl restart sysstat.service\n\n# Docker 仓库登录（密码明文存储存在安全风险）\necho \"尝试登录 Docker 仓库...\"\ndocker login --username wanyuxiang000@163.com \\\n    --password Xiang5326865 \\\n    registry.cn-shenzhen.aliyuncs.com\n\n#更新docker别名\necho \"更新docker别名\"\nalias dlog=\'docker logs -f --tail 200\'\nsource source ~/.bashrc\n\necho \"所有组件安装完成！\"', 9, '新主机初始化', '2025-08-20 21:39:37', '2025-08-20 21:39:37');
